import{_ as t,o,c as n,ae as a}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Configure SSO With Okta","description":"","frontmatter":{"title":"Configure SSO With Okta","slug":"configure-sso-with-okta"},"headers":[],"relativePath":"account-hub/configure-sso-with-okta.md","filePath":"account-hub/configure-sso-with-okta.md"}'),r={name:"account-hub/configure-sso-with-okta.md"};function i(s,e,l,c,u,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>This guide provides step-by-step instructions for setting up Single Sign-On (SSO) with Branch using <strong>Okta</strong> as your Identity Provider (IdP).</p><p>This guide will:</p><ol><li>Help you get your configuration details from Branch.</li><li>Show you how to create and configure a SAML 2.0 application in Okta.</li><li>Link you back to the main <a href="./configure-sso.html">Configure SSO guide</a> to complete the setup.</li></ol><h2 id="configure-sso" tabindex="-1">Configure SSO <a class="header-anchor" href="#configure-sso" aria-label="Permalink to &quot;Configure SSO&quot;">​</a></h2><p>To configure SSO, you’ll need to get your unique URLs from Branch, configure Okta, and then finish the setup in Branch.</p><h3 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h3><p>Before you begin, ensure you have:</p><ul><li><p>Admin access to your Branch account.</p></li><li><p>Admin access to your Okta account.</p></li><li><p>SSO enabled for your account.</p><ul><li>Access to SSO requires a Branch plan. Please visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page or <a href="https://branchdocs.app.link/e/sso-sign-up" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</li></ul></li></ul><h3 id="step-1-get-configuration-details-from-branch" tabindex="-1">Step 1: Get configuration details from Branch <a class="header-anchor" href="#step-1-get-configuration-details-from-branch" aria-label="Permalink to &quot;Step 1: Get configuration details from Branch&quot;">​</a></h3><p>This step is different depending on whether you are on the <a href="./branch-dashboard-overview.html">legacy</a> or <a href="./new-branch-overview.html">new</a> Branch experience. The rest of the steps remain the same between the two platforms.</p><h3 id="step-2-configure-okta-saml" tabindex="-1">Step 2: Configure Okta SAML <a class="header-anchor" href="#step-2-configure-okta-saml" aria-label="Permalink to &quot;Step 2: Configure Okta SAML&quot;">​</a></h3><p>Now, log in to your Okta admin dashboard to create the Branch application.</p><ol><li><p>In Okta, navigation to <strong>Applications</strong> → <strong>Applications</strong> and select <strong>Create App Integration</strong>.</p><ol start="2"><li>Select <strong>SAML 2.0</strong> as the sign-on method and click <strong>Next</strong>.</li></ol></li><li><p>On the <strong>General Settings</strong> page, enter an app name (e.g., “Branch”) and click <strong>Next</strong>.</p></li><li><p>On the <strong>Configure SAML</strong> page, in the <strong>General</strong> section, fill in the fields using the values from the Branch tab you kept open from step 1.</p><ol start="3"><li>Single sign-on URI: Paste the <code>Single Sign-On URL</code>from Branch.</li><li>Audience URI (SP Entity ID): Paste the <code>Service Provider Entity ID</code> from Branch.</li></ol></li><li><p>In the same section, configure the following Okta settings:</p><ol start="3"><li>Name ID format: Set to <code>EmailAddress</code></li><li>Application username: Set to <code>Email</code><br><em>[Image: Configuration settings for SAML integration in Okta for Branch.]</em>.png)</li></ol></li></ol><h3 id="step-3-map-attributes-in-okta" tabindex="-1">Step 3: Map attributes in Okta <a class="header-anchor" href="#step-3-map-attributes-in-okta" aria-label="Permalink to &quot;Step 3: Map attributes in Okta&quot;">​</a></h3><p>Branch requires three attributes to be sent in the SAML response to provision and identify users.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>To set up a successful mapping, you must use the attribute names <code>firstName</code>, <code>lastName</code>, and <code>email</code> exactly as they are capitalized and spelled here. Do not use URN or OID formats.</p></div><table tabindex="0"><thead><tr><th><strong>Name</strong></th><th><strong>Value (Example)</strong></th></tr></thead><tbody><tr><td><code>firstName</code></td><td><code>user.firstName</code></td></tr><tr><td><code>lastName</code></td><td><code>user.lastName</code></td></tr><tr><td><code>email</code></td><td><code>user.email</code></td></tr></tbody></table><ol><li><p>Still on Okta’s <strong>Configure SAML</strong> screen, scroll down to the <strong>Attribute Statements (Optional)</strong> section.</p></li><li><p>Add the following three attributes and corresponding values. Make sure you enter the names <em>exactly</em> as spelled and cased here.</p></li><li><p>Select <strong>Next</strong> and then <strong>Finish</strong> to save your Okta application.</p></li></ol><h3 id="step-4-complete-connection-in-branch" tabindex="-1">Step 4: Complete connection in Branch <a class="header-anchor" href="#step-4-complete-connection-in-branch" aria-label="Permalink to &quot;Step 4: Complete connection in Branch&quot;">​</a></h3><p>Your Okta application is now configured. The final step is to provide Okta’s metadata to Branch and test the connection.</p><ol><li>In your new Okta application, go to the <strong>Sign On</strong> tab.</li><li>Find the <strong>SAML setup instructions</strong> and select <strong>View SAML setup instructions</strong>.</li><li>A new page will open with your metadata. Copy the <strong>Identity Provider Single Sign-On URL</strong> or the <strong>Metadata URL</strong>.</li><li>Go back to your Branch <strong>Configure Custom SAML</strong> browser tab.</li><li>Complete step <a href="https://help.branch.io/docs/configure-sso#:~:text=Step%202.3%3A%20Configure%20connection" target="_blank" rel="noreferrer">2.3</a> in our main guide. Paste your Okta <strong>Metadata URL</strong> (recommended) or manually enter the <strong>Single Sign-On URL</strong> and upload the <strong>Signing Certificate</strong> (also found on the Okta setup instructions page).</li></ol><h3 id="step-5-test-sso" tabindex="-1">Step 5: Test SSO <a class="header-anchor" href="#step-5-test-sso" aria-label="Permalink to &quot;Step 5: Test SSO&quot;">​</a></h3><p>Test and enable your connection using step <a href="./configure-sso.html#step-24-test-sso">2.4</a> in our main guide.</p><h2 id="more-information" tabindex="-1">More information <a class="header-anchor" href="#more-information" aria-label="Permalink to &quot;More information&quot;">​</a></h2><p>For more complete information about configuring SSO for Branch, visit our <a href="./configure-sso.html">Configure SSO (General SAML) guide</a>.</p>',26)])])}const g=t(r,[["render",i]]);export{p as __pageData,g as default};
